'<script>',
'document.addEventListener("DOMContentLoaded", function () {',
'',
'  var usuario = apex.env.APP_USER;',
'',
'  if (usuario === "TRIBUNAL") {',
'',
unistr('    // Ocultar men\00FA lateral'),
'    var nav = document.getElementById("t_Body_nav");',
'    if (nav) nav.style.display = "none";',
'',
'    var tree = document.getElementById("t_TreeNav");',
'    if (tree) tree.style.display = "none";',
'',
'    // Forzar layout sin sidebar (solo esto)',
'    var body = document.getElementById("t_PageBody");',
'    if (body) {',
'      body.classList.add("t-PageBody--hideLeft");',
'      body.classList.remove("apex-side-nav");',
'    }',
'',
unistr('    // Ocultar bot\00F3n hamburguesa'),
'    var btn = document.getElementById("t_Button_navControl");',
'    if (btn) btn.style.display = "none";',
'  }',
'',
'});',
'</script>'))
,p_attributes=>wwv_flow_t_plugin_attributes(wwv_flow_t_varchar2(
