'/* ========================================================',
unistr('   \D83C\DFA8 PALETA GLOBAL \2013 MUNICIPALIDAD'),
'======================================================== */',
':root {',
'  --naranja-profesional: #e88b00;',
'  --verde-profesional: #009c7a;',
'  --verde-hover: #00b28a;',
'',
'  --gris-fondo: #f5f5f5;',
'  --gris-texto: #2f2f2f;',
'  --gris-medio: #6e6e6e;',
'',
'  --blanco: #ffffff;',
'',
'  --borde-claro: #d9d9d9;',
'  --sombra-suave: rgba(0, 0, 0, 0.06);',
'}',
'',
'/* ========================================================',
unistr('   \D83C\DF0C FONDO GENERAL'),
'======================================================== */',
'body,',
'.t-Body {',
'  background-color: var(--gris-fondo);',
'  color: var(--gris-texto);',
'}',
'',
'/* ========================================================',
unistr('   \D83E\DDF1 HEADER APEX'),
'======================================================== */',
'.t-Header {',
'  background: linear-gradient(',
'    to right,',
'    var(--naranja-profesional),',
'    var(--verde-profesional)',
'  );',
'  color: var(--blanco);',
'  border-bottom: 1px solid rgba(0, 0, 0, 0.1);',
'}',
'',
'/* ========================================================',
unistr('   \D83E\DDCA INPUTS'),
'======================================================== */',
'input[type="text"],',
'input[type="search"],',
'input[type="file"],',
'input[type="date"],',
'textarea,',
'select,',
'.a-Select,',
'.apex-item-select {',
'  width: 100% !important;',
'  padding: 8px 12px !important;',
'  font-size: 14px !important;',
'  border-radius: 6px !important;',
'  border: 1px solid var(--borde-claro) !important;',
'  background-color: var(--blanco) !important;',
'  color: var(--gris-texto) !important;',
'  box-sizing: border-box !important;',
'  height: auto !important;',
'  box-shadow: none !important;',
'}',
'',
'textarea {',
'  min-height: 90px;',
'}',
'',
'/* ========================================================',
unistr('   \D83C\DFF7\FE0F LABELS'),
'======================================================== */',
'.apex-item-label,',
'.t-Form-label {',
'  font-size: 13px;',
'  font-weight: 500;',
'  color: var(--gris-texto);',
'  margin-bottom: 4px;',
'}',
'',
'/* ========================================================',
unistr('   \D83D\DCD0 GRILLA APEX'),
'======================================================== */',
'.t-Region-body {',
'  display: block;',
'}',
'',
'.t-Form-fieldContainer,',
'.t-Form-inputContainer,',
'.t-Form-itemWrapper {',
'  max-width: none !important;',
'  width: 100% !important;',
'  margin: 0 !important;',
'  box-sizing: border-box;',
'}',
'',
'/* ========================================================',
unistr('   \D83D\DD36 BOTONES'),
'======================================================== */',
'.t-Button,',
'button {',
'  background-color: var(--naranja-profesional) !important;',
'  color: var(--blanco) !important;',
'  font-weight: 600;',
'  padding: 8px 18px;',
'  font-size: 14px;',
'  border-radius: 8px;',
'  border: none !important;',
'  box-shadow: 0 2px 6px var(--sombra-suave);',
'  transition: background 0.25s ease, transform 0.15s ease;',
'}',
'',
'.t-Button:hover,',
'button:hover {',
'  background-color: #ff9e1f !important;',
'  transform: translateY(-1px);',
'}',
'',
'.t-Button--hot {',
'  background-color: var(--verde-profesional) !important;',
'}',
'',
'/* ========================================================',
unistr('   \D83D\DEAB OCULTAR CABECERAS'),
'======================================================== */',
'.ocultar-cabecera .t-Region-header,',
'.t-BreadcrumbRegion {',
'  display: none !important;',
'}',
'',
'/* ========================================================',
unistr('   \D83C\DF9E\FE0F ANIMACIONES'),
'======================================================== */',
'@keyframes entrada-suave {',
'  from { opacity: 0; transform: translateY(12px); }',
'  to { opacity: 1; transform: translateY(0); }',
'}',
'',
'.t-Region {',
'  animation: entrada-suave 0.35s ease-out both;',
'}',
'',
'/* ========================================================',
unistr('   \D83D\DCCD BOTONES DERECHA'),
'======================================================== */',
'.t-Region-buttons,',
'.t-ButtonRegion,',
'.t-ButtonRegion-col {',
'  display: flex !important;',
'  justify-content: flex-end !important;',
'}',
'',
'.t-Button {',
'  float: right !important;',
'}',
'',
'/* ========================================================',
unistr('   \D83D\DCC1 CARD EXPEDIENTE'),
'======================================================== */',
'.card-expediente {',
'  background: var(--blanco);',
'  border-radius: 10px;',
'  padding: 22px 24px;',
'  margin-bottom: 22px;',
'  border: 1px solid var(--borde-claro);',
'  box-shadow: 0 2px 10px var(--sombra-suave);',
'  color: var(--gris-texto);',
'}',
'',
'.card-expediente .t-Region-title {',
'  font-size: 18px;',
'  font-weight: 600;',
'  margin-bottom: 14px;',
'  color: var(--gris-texto);',
'}',
'',
'/* ========================================================',
unistr('   \D83D\DCE6 BOT\00D3N EXPEDIENTE'),
'======================================================== */',
'.btn-expediente {',
'  margin-top: 14px !important;',
'  width: 100% !important;',
'  height: 38px !important;',
'  border-radius: 8px !important;',
'  font-weight: 600;',
'  background: var(--naranja-profesional) !important;',
'  color: var(--blanco) !important;',
'  border: none !important;',
'  box-shadow: 0 2px 6px var(--sombra-suave);',
'  transition: background 0.2s ease, transform 0.15s ease;',
'}',
'',
'.btn-expediente:hover {',
'  background: #ff9e1f !important;',
'  transform: translateY(-1px);',
'}',
'',
'/* ========================================================',
unistr('   \D83D\DCCB ACTION CARDS'),
'======================================================== */',
'.action-group {',
'  display: flex;',
'  flex-direction: column;',
'  gap: 14px;',
'  margin-top: 10px;',
'}',
'',
'.action-card {',
'  display: flex;',
'  align-items: center;',
'  justify-content: space-between;',
'  background: var(--blanco);',
'  border: 1px solid var(--borde-claro);',
'  border-radius: 10px;',
'  padding: 14px 18px;',
'  box-shadow: 0 2px 6px var(--sombra-suave);',
'}',
'',
'.action-icon {',
'  font-size: 22px;',
'  color: var(--verde-profesional);',
'  margin-right: 14px;',
'}',
'',
'.action-content {',
'  flex-grow: 1;',
'}',
'',
'.action-title {',
'  font-size: 15px;',
'  font-weight: 600;',
'  color: var(--gris-texto);',
'}',
'',
'.action-sub {',
'  font-size: 13px;',
'  color: var(--gris-medio);',
'  margin-top: 2px;',
'}',
'',
'.action-btn {',
'  background: var(--verde-profesional);',
'  color: var(--blanco);',
'  border: none;',
'  border-radius: 6px;',
'  padding: 8px 14px;',
'  cursor: pointer;',
'  display: flex;',
'  align-items: center;',
'  gap: 6px;',
'  font-size: 14px;',
'  font-weight: 500;',
'}',
'',
'.action-btn:hover {',
'  background: var(--verde-hover);',
'}',
'',
'',
'',
'',
'',
'',
'',
'',
'.action-group {',
'  display: grid !important;',
'  grid-template-columns: repeat(2, 1fr);',
'  gap: 18px;',
'}',
'',
'/* En pantallas chicas vuelve a 1 columna */',
'@media (max-width: 768px) {',
'  .action-group {',
'    grid-template-columns: 1fr;',
'  }',
'}',
''))
,p_page_template_options=>'#DEFAULT#'
,p_protection_level=>'C'
,p_page_component_map=>'13'
