wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(110580860743647026021)
,p_process_sequence=>90
,p_process_point=>'ON_SUBMIT_BEFORE_COMPUTATION'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'PRC_GUARDAR_MULTA'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_id_persona        NUMBER;',
'    v_id_vehiculo       NUMBER;',
'    v_id_animal         NUMBER;',
'    v_id_inmueble       NUMBER;',
'    v_id_acta           NUMBER;',
'    v_numero_acta       NUMBER;',
'    v_numero_acta_txt   VARCHAR2(20);',
'    v_blob_foto         BLOB;',
'BEGIN',
'    /* =========================',
'       PERSONAS (REUTILIZABLE)',
'    ========================= */',
'    IF :P2_DNI IS NOT NULL THEN',
'        BEGIN',
'            SELECT id_persona',
'            INTO v_id_persona',
'            FROM personas',
'            WHERE dni = :P2_DNI;',
'',
'        EXCEPTION',
'            WHEN NO_DATA_FOUND THEN',
'                INSERT INTO personas (',
'                    DNI, NOMBRE, APELLIDO,',
'                    FECHA_NACIMIENTO, LOCALIDAD,',
'                    CALLE, NUMERO, CODIGO_POSTAL,',
'                    TELEFONO, CORREO',
'                ) VALUES (',
'                    :P2_DNI, :P2_NOMBRE, :P2_APELLIDO,',
'                    :P2_FECHA_NACIMIENTO, :P2_LOCALIDAD,',
'                    :P2_CALLE, :P2_NUMERO, :P2_CODIGO_POSTAL,',
'                    :P2_TELEFONO, :P2_CORREO',
'                )',
'                RETURNING ID_PERSONA INTO v_id_persona;',
'        END;',
'    END IF;',
'',
'    /* =========================',
'       VEHICULO',
'    ========================= */',
'    IF :P2_TIPO_ACTA = ''VEHICULOS'' THEN',
'        INSERT INTO VEHICULOS (',
'            PATENTE, MARCA, MODELO,',
'            COLOR, TIPO_VEHICULO,',
'            CATEGORIA, ANIO_FABRICACION,',
'            ID_TITULAR',
'        ) VALUES (',
'            :P2_PATENTE, :P2_MARCA, :P2_MODELO,',
'            :P2_COLOR, :P2_TIPO_VEHICULO,',
'            :P2_CATEGORIA, :P2_ANIO_FABRICACION,',
'            v_id_persona',
'        )',
'        RETURNING ID_VEHICULO INTO v_id_vehiculo;',
'    END IF;',
'',
'    /* =========================',
'       ANIMAL',
'    ========================= */',
'    IF :P2_TIPO_ACTA = ''ANIMAL'' THEN',
'        INSERT INTO ANIMALES (',
'            RAZA, ESPECIE, SEXO,',
'            ID_PROPIETARIO',
'        ) VALUES (',
'            :P2_RAZA, :P2_ESPECIE, :P2_SEXO,',
'            v_id_persona',
'        )',
'        RETURNING ID_ANIMAL INTO v_id_animal;',
'    END IF;',
'',
'    /* =========================',
'       INMUEBLE',
'    ========================= */',
'    IF :P2_TIPO_ACTA = ''INMUEBLES'' THEN',
'        INSERT INTO INMUEBLES (',
'            NOMENCLATURA, CUIL, RAZON_SOCIAL,',
'            CALLE, NUMERO, MANZANA,',
'            SECCION, PARCELA,',
'            TIPO_INMUEBLE, USO_INMUEBLE,',
'            METROS_CUADRADOS',
'        ) VALUES (',
'            :P2_NOMENCLATURA, :P2_CUIL, :P2_RAZON_SOCIAL,',
'            :P2_CALLE_1, :P2_NUMERO_1, :P2_MANZANA,',
'            :P2_SECCION, :P2_PARCELA,',
'            :P2_TIPO_INMUEBLE, :P2_USO_INMUEBLE,',
'            :P2_METROS_CUADRADOS',
'        )',
'        RETURNING ID_INMUEBLE INTO v_id_inmueble;',
'    END IF;',
'',
'    /* =========================',
'       NUMERO DE ACTA (SECUENCIA)',
'    ========================= */',
'    SELECT SEQ_NUMERO_ACTA.NEXTVAL',
'    INTO v_numero_acta',
'    FROM DUAL;',
'',
'    /* Formato visual 0000/2025 */',
'    v_numero_acta_txt :=',
'        LPAD(v_numero_acta, 4, ''0'')',
'        || ''/''',
'        || TO_CHAR(SYSDATE, ''YYYY'');',
'',
'    /* =========================',
'       FOTO (BLOB)',
'    ========================= */',
'    IF :P2_FOTO_INFRACCION IS NOT NULL THEN',
'        SELECT blob_content',
'        INTO v_blob_foto',
'        FROM apex_application_temp_files',
'        WHERE name = :P2_FOTO_INFRACCION;',
'    END IF;',
'',
'    /* =========================',
'       ACTA (NUCLEO)',
'    ========================= */',
'    INSERT INTO ACTAS (',
'        NUMERO_ACTA,',
'        ID_PERSONA,',
'        ID_VEHICULO,',
'        ID_INMUEBLE,',
'        ID_ANIMAL,',
'        TIPO_ACTA,',
'        ID_MOTIVO,',
'        ID_INSPECTOR,',
'        FECHA_INFRACCION,',
'        LUGAR_INFRACCION,',
'        DESCRIPCION,',
'        UF,',
'        FOTO_INFRACCION,',
'        IMPORTE,',
'        ESTADO',
'    ) VALUES (',
'        v_numero_acta,',
'        v_id_persona,',
'        v_id_vehiculo,',
'        v_id_inmueble,',
'        v_id_animal,',
'        :P2_TIPO_ACTA,',
'        :P2_ID_MOTIVOS,',
'        :P2_ID_INSPECTOR,',
'        :P2_FECHA_INFRACCION,',
'        :P2_LUGAR_INFRACCION,',
'        :P2_DESCRIPCION,',
'        :P2_UF,',
'        v_blob_foto,',
'        :P2_IMPORTE,',
'        ''PENDIENTE''',
'    )',
'    RETURNING ID_ACTA INTO v_id_acta;',
'',
'    /* =========================',
'       ITEMS DE PAGINA',
'    ========================= */',
'    :P2_ID_ACTA     := v_id_acta;',
'    :P2_NUMERO_ACTA := v_numero_acta_txt;',
'',
'    /* =========================',
'       DOCUMENTACION',
'    ========================= */',
'    INSERT INTO DOCUMENTACION (',
'        ID_ACTA,',
'        FECHA_GENERACION,',
'        USUARIO_GENERA',
'    ) VALUES (',
'        v_id_acta,',
'        SYSDATE,',
'        :P2_USUARIO_GENERA',
'    );',
'',
'END;',
''))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(100787688946807058833)
,p_internal_uid=>110580860743647026021
);
end;
