,p_location=>null
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'<style>',
'  .cabecera-municipalidad {',
'    position: relative;',
'    display: flex;',
'    justify-content: space-between;',
'    align-items: center;',
'',
