'      #1aa57a,',
'      #1f7fbf,',
'      #f0c431',
'    );',
'',
'    padding: 15px 20px;',
'    border-radius: 10px;',
'    box-shadow: 0 2px 6px var(--sombra-suave);',
'    margin-bottom: 20px;',
