,p_plug_name=>'RESUMEN'
,p_plug_display_sequence=>60
,p_location=>null
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'<div style="padding: 1rem; background-color: #f0f8ff; border: 1px solid #ccc; border-radius: 6px; text-align: center;">',
'  <strong>La consulta realizada no registra deudas en este Municipio.</strong>',
'</div>',
''))
,p_plug_display_condition_type=>'EXPRESSION'
,p_plug_display_when_condition=>wwv_flow_string.join(wwv_flow_t_varchar2(
':REQUEST = ''BUSCAR''',
'AND',
'(',
'    (',
'        UPPER(:P5_TRAMITE) = ''GENERAL''',
'        AND :P5_IDENTIFICADOR IS NOT NULL',
'        AND UPPER(:P5_CONSULTA) IN (''DNI'',''PATENTE'',''NOMENCLATURA'')',
'',
'        AND NOT EXISTS (',
'            SELECT 1',
'            FROM vw_multas_busqueda_completa',
'            WHERE',
'                (',
'                    ( UPPER(:P5_CONSULTA) = ''DNI''',
'                      AND dni = :P5_IDENTIFICADOR )',
'',
'                 OR ( UPPER(:P5_CONSULTA) = ''PATENTE''',
'                      AND id_vehiculo IS NOT NULL',
'                      AND UPPER(patente) LIKE ''%'' || UPPER(:P5_IDENTIFICADOR) || ''%'' )',
'',
'                 OR ( UPPER(:P5_CONSULTA) = ''NOMENCLATURA''',
'                      AND id_inmueble IS NOT NULL',
'                      AND UPPER(nomenclatura) LIKE ''%'' || UPPER(:P5_IDENTIFICADOR) || ''%'' )',
'                )',
'        )',
'    )',
'    OR',
'    (',
'        UPPER(:P5_TRAMITE) = ''CARNET''',
'        AND :P5_IDENTIFICADOR IS NOT NULL',
'',
'        AND NOT EXISTS (',
'            SELECT 1',
'            FROM vw_multas_busqueda_completa',
'            WHERE',
'                id_vehiculo IS NOT NULL',
'                AND vehiculo_id_titular = id_persona',
'                AND dni = :P5_IDENTIFICADOR',
'        )',
'    )',
')'))
,p_plug_display_when_cond2=>'SQL'
,p_required_patch=>wwv_flow_imp.id(98852224542628674370)
,p_attributes=>wwv_flow_t_plugin_attributes(wwv_flow_t_varchar2(
  'expand_shortcuts', 'N',
