wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(120320082925006346010)
,p_plug_name=>'Consulta de multas'
,p_region_css_classes=>'ocultar-vacia'
,p_region_template_options=>'#DEFAULT#:t-IRR-region--hideHeader js-addHiddenHeadingRoleDesc'
,p_plug_template=>2100526641005906379
,p_plug_display_sequence=>70
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    id_acta,',
'    numero_acta,',
'    fecha_infraccion,',
'    dni,',
'    patente,',
'    especie,',
'    raza,',
'    nomenclatura,',
'    motivo_descripcion AS motivo,',
'    importe            AS monto,',
'    estado',
'FROM vw_multas_busqueda_completa',
'WHERE',
'(',
'    -- =========================',
'    -- CARNET',
'    -- =========================',
'    UPPER(:P5_TRAMITE) = ''CARNET''',
'    AND :P5_IDENTIFICADOR IS NOT NULL',
'    AND id_vehiculo IS NOT NULL',
'    AND vehiculo_id_titular = id_persona',
'    AND dni = :P5_IDENTIFICADOR',
')',
'OR',
'(',
'    -- =========================',
'    -- GENERAL',
'    -- =========================',
'    UPPER(:P5_TRAMITE) = ''GENERAL''',
'    AND :P5_IDENTIFICADOR IS NOT NULL',
'    AND',
'    (',
'        -- DNI exacto',
'        ( UPPER(:P5_CONSULTA) = ''DNI''',
'          AND dni = :P5_IDENTIFICADOR )',
'',
'        -- PATENTE exacta',
'     OR ( UPPER(:P5_CONSULTA) = ''PATENTE''',
'          AND id_vehiculo IS NOT NULL',
'          AND UPPER(TRIM(patente)) = UPPER(TRIM(:P5_IDENTIFICADOR)) )',
'',
'        -- NOMENCLATURA exacta',
'     OR ( UPPER(:P5_CONSULTA) = ''NOMENCLATURA''',
'          AND id_inmueble IS NOT NULL',
'          AND UPPER(TRIM(nomenclatura)) = UPPER(TRIM(:P5_IDENTIFICADOR)) )',
'',
'        -- ANIMAL (si aplica)',
'     OR ( UPPER(:P5_CONSULTA) = ''ANIMAL''',
'          AND id_animal IS NOT NULL',
'          AND UPPER(TRIM(especie)) = UPPER(TRIM(:P5_IDENTIFICADOR)) )',
'    )',
')',
'ORDER BY fecha_infraccion DESC;',
'',
''))
,p_plug_source_type=>'NATIVE_IR'
,p_ajax_items_to_submit=>'P5_TRAMITE,P5_CONSULTA,P5_IDENTIFICADOR'
,p_prn_page_header=>'Consulta de multas'
