wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(124419694714901556011)
,p_plug_name=>unistr('Resultados \2013 General por DNI')
,p_region_template_options=>'#DEFAULT#:t-IRR-region--hideHeader js-addHiddenHeadingRoleDesc'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>2100526641005906379
,p_plug_display_sequence=>90
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    id_acta,',
'    numero_acta,',
'    tipo_acta,',
'    estado,',
'    fecha_infraccion,',
'    dni,',
'    motivo_descripcion AS motivo,',
'    importe            AS monto',
'FROM vw_multas_busqueda_completa',
'WHERE',
'    /* Solo cuando corresponde */',
'    UPPER(:P5_TRAMITE) = ''GENERAL''',
'AND UPPER(:P5_CONSULTA) = ''DNI''',
'AND :P5_IDENTIFICADOR IS NOT NULL',
'',
'    /* Coincidencia EXACTA de DNI */',
'AND dni = :P5_IDENTIFICADOR',
'',
'    /* Ocultar multas finalizadas */',
'AND UPPER(estado) <> ''RESUELTA''',
'',
'ORDER BY fecha_infraccion DESC;',
''))
