wwv_flow_imp_page.create_page_button(
 p_id=>wwv_flow_imp.id(120260014918977182208)
,p_button_sequence=>60
,p_button_name=>'LIBRE_MULTA'
,p_button_action=>'REDIRECT_PAGE'
,p_button_template_options=>'#DEFAULT#'
,p_button_template_id=>4072362960822175091
,p_button_image_alt=>'Generar libre de multa'
,p_button_redirect_url=>'f?p=&APP_ID.:20:&SESSION.::&DEBUG.::P20_CONSULTA:'
,p_button_condition=>wwv_flow_string.join(wwv_flow_t_varchar2(
'/* =========================',
'   CASO 1: GENERAL sin multas',
'========================= */',
'(',
'    UPPER(:P5_TRAMITE) = ''GENERAL''',
'    AND :P5_IDENTIFICADOR IS NOT NULL',
'    AND UPPER(:P5_CONSULTA) IN (''DNI'',''PATENTE'',''NOMENCLATURA'')',
'',
'    AND NOT EXISTS (',
'        SELECT 1',
'        FROM vw_multas_busqueda_completa',
'        WHERE',
'            (',
'                ( UPPER(:P5_CONSULTA) = ''DNI''',
'                  AND dni = :P5_IDENTIFICADOR )',
'',
'             OR ( UPPER(:P5_CONSULTA) = ''PATENTE''',
'                  AND id_vehiculo IS NOT NULL',
'                  AND UPPER(patente) LIKE ''%'' || UPPER(:P5_IDENTIFICADOR) || ''%'' )',
'',
'             OR ( UPPER(:P5_CONSULTA) = ''NOMENCLATURA''',
'                  AND id_inmueble IS NOT NULL',
'                  AND UPPER(nomenclatura) LIKE ''%'' || UPPER(:P5_IDENTIFICADOR) || ''%'' )',
'            )',
'    )',
')',
'',
'/* =========================',
'   CASO 2: CARNET sin multas',
'========================= */',
'OR',
'(',
