 p_id=>wwv_flow_imp.id(125011683069915159329)
,p_plug_name=>unistr('Acta de Infracci\00F3n')
,p_plug_display_sequence=>20
,p_location=>null
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'<script src="https://cdnjs.cloudflare.com/ajax/libs/html2pdf.js/0.10.1/html2pdf.bundle.min.js"></script>',
'',
'<div id="pdf_acta" style="',
'  font-family: Arial, sans-serif;',
'  font-size: 12px;',
'  color: #000;',
'  max-width: 800px;',
'  margin: 0 auto;',
'  background: #fff;',
'  padding: 20px;',
'  border: 1px solid #000;',
'">',
'',
'  <!-- ENCABEZADO -->',
'  <div style="display:flex; align-items:center; gap:15px; margin-bottom:10px;">',
'    <img src="#APP_FILES#Logo muni.png" style="height:50px;">',
'    <div>',
'      <div style="font-weight:bold;">MUNICIPALIDAD DE CASILDA</div>',
unistr('      <div>Departamento de Tr\00E1nsito</div>'),
unistr('      <div style="font-size:11px;">Acta / Multa de Infracci\00F3n</div>'),
'    </div>',
'  </div>',
'',
'  <div style="text-align:center; font-size:16px; font-weight:bold; margin:10px 0;">',
'    MULTA',
'  </div>',
'',
'  <!-- FILA 1 -->',
'  <table style="width:100%; border-collapse:collapse; margin-bottom:6px;">',
'    <tr>',
'      <td style="border:1px solid #000; padding:6px;">',
'        <b>Unidad:</b><br>',
unistr('        Tr\00E1nsito Municipal'),
'      </td>',
'      <td style="border:1px solid #000; padding:6px;">',
unistr('        <b>Fecha de Emisi\00F3n:</b><br>'),
'        &P6_FECHA_GENERACION.',
'      </td>',
'      <td style="border:1px solid #000; padding:6px;">',
unistr('        <b>Fecha Infracci\00F3n:</b><br>'),
'        &P6_FECHA_INFRACCION.',
'      </td>',
'      <td style="border:1px solid #000; padding:6px; text-align:center;">',
'        <b>Importe</b><br>',
'        <span style="font-size:18px; font-weight:bold;">',
'          $ &P6_IMPORTE.',
'        </span>',
'      </td>',
'    </tr>',
'  </table>',
'',
'  <!-- CONTRIBUYENTE -->',
'  <table style="width:100%; border-collapse:collapse; margin-bottom:6px;">',
'    <tr>',
'      <td style="border:1px solid #000; padding:6px; width:40%;">',
'        <b>Contribuyente</b><br>',
'        &P6_PERSONA_APELLIDO. &P6_PERSONA_NOMBRE.',
'      </td>',
'      <td style="border:1px solid #000; padding:6px; width:20%;">',
'        <b>DNI</b><br>',
'        &P6_DNI.',
'      </td>',
'      <td style="border:1px solid #000; padding:6px; width:40%;">',
'        <b>Domicilio</b><br>',
unistr('        &P6_PERSONA_CALLE. &P6_PERSONA_NUMERO. \2013 &P6_LOCALIDAD.'),
'      </td>',
'    </tr>',
'  </table>',
'',
unistr('  <!-- VEH\00CDCULO / INMUEBLE -->'),
'  <table style="width:100%; border-collapse:collapse; margin-bottom:6px;">',
'    <tr>',
'      <td style="border:1px solid #000; padding:6px;">',
'        <b>Patente</b><br>',
'        &P6_PATENTE.',
'      </td>',
'      <td style="border:1px solid #000; padding:6px;">',
'        <b>Marca / Modelo</b><br>',
'        &P6_MARCA. &P6_MODELO.',
'      </td>',
'      <td style="border:1px solid #000; padding:6px;">',
'        <b>Nomenclatura</b><br>',
'        &P6_NOMENCLATURA.',
'      </td>',
'    </tr>',
'  </table>',
'',
unistr('  <!-- DATOS DE LA INFRACCI\00D3N -->'),
'  <table style="width:100%; border-collapse:collapse; margin-bottom:6px;">',
'    <tr>',
'      <td style="border:1px solid #000; padding:6px;">',
'        <b>Motivo</b><br>',
'        &P6_MOTIVO_DESCRIPCION.',
'      </td>',
'    </tr>',
'    <tr>',
'      <td style="border:1px solid #000; padding:6px;">',
unistr('        <b>Lugar de Infracci\00F3n</b><br>'),
'        &P6_LUGAR_INFRACCION.',
'      </td>',
'    </tr>',
'    <tr>',
'      <td style="border:1px solid #000; padding:6px;">',
unistr('        <b>Descripci\00F3n</b><br>'),
'        &P6_DESCRIPCION_ACTA.',
'      </td>',
'    </tr>',
'  </table>',
'',
'  <!-- OBSERVACIONES -->',
'  <div style="font-size:11px; margin-top:8px;">',
'    El pago de la presente multa no exime otras responsabilidades legales.',
'    Conserve este comprobante.',
'  </div>',
'',
'  <!-- SEPARADOR -->',
'  <div style="border-top:1px dashed #000; margin:18px 0;"></div>',
'',
'  <!-- PIE -->',
'  <div style="display:flex; justify-content:space-between; font-size:11px;">',
'    <div>',
'      Inspector: &P6_INSPECTOR_APELLIDO. &P6_INSPECTOR_NOMBRE.<br>',
'      Departamento: &P6_DEPARTAMENTO.',
'    </div>',
'    <div style="text-align:right;">',
unistr('      N\00BA Acta: <b>&P6_NUMERO_ACTA.</b><br>'),
'      Estado: <b>&P6_ESTADO.</b>',
'    </div>',
'  </div>',
'</div>',
'',
unistr('<!-- BOT\00D3N PDF -->'),
'<div style="text-align:center; margin-top:15px;">',
'  <button type="button" onclick="descargarPDF()"',
'    style="padding:10px 20px; font-weight:bold; border:none;',
'           background:#000; color:#fff; cursor:pointer;">',
'    Descargar PDF',
'  </button>',
'</div>',
'',
'<script>',
'function descargarPDF(){',
'  const element = document.getElementById(''pdf_acta'');',
'  html2pdf().set({',
'    margin: 8,',
'    filename: ''Acta_'' + ''&P6_NUMERO_ACTA.'' + ''.pdf'',',
'    image: { type: ''jpeg'', quality: 0.98 },',
'    html2canvas: { scale: 2, useCORS: true },',
'    jsPDF: { unit: ''mm'', format: ''a4'', orientation: ''portrait'' }',
'  }).from(element).save();',
'}',
'</script>',
'',
'',
''))
,p_attributes=>wwv_flow_t_plugin_attributes(wwv_flow_t_varchar2(
  'expand_shortcuts', 'N',
  'output_as', 'HTML')).to_clob
);
