wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(125016690674766289648)
,p_process_sequence=>10
,p_process_point=>'BEFORE_HEADER'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Cargar Acta'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'BEGIN',
'  IF :P6_ID_ACTA_1 IS NOT NULL THEN',
'    SELECT',
'      *',
'    INTO',
'      :P6_ID_ACTA_1,',
'      :P6_NUMERO_ACTA,',
'      :P6_TIPO_ACTA,',
'      :P6_FECHA_INFRACCION,',
'      :P6_LUGAR_INFRACCION,',
'      :P6_DESCRIPCION_ACTA,',
'      :P6_UF,',
'      :P6_IMPORTE,',
'      :P6_ESTADO,',
'      :P6_ID_PERSONA,',
'      :P6_ID_VEHICULO,',
'      :P6_ID_INMUEBLE,',
'      :P6_ID_ANIMAL,',
'      :P6_ID_MOTIVO,',
'      :P6_ID_INSPECTOR,',
'      :P6_DNI,',
'      :P6_PERSONA_NOMBRE,',
'      :P6_PERSONA_APELLIDO,',
'      :P6_FECHA_NACIMIENTO,',
'      :P6_LOCALIDAD,',
'      :P6_PERSONA_CALLE,',
'      :P6_PERSONA_NUMERO,',
'      :P6_PERSONA_CP,',
'      :P6_PERSONA_TELEFONO,',
'      :P6_PERSONA_CORREO,',
'      :P6_PATENTE,',
'      :P6_MARCA,',
'      :P6_MODELO,',
'      :P6_COLOR,',
'      :P6_TIPO_VEHICULO,',
'      :P6_CATEGORIA,',
'      :P6_ANIO_FABRICACION,',
'      :P6_VEHICULO_ID_TITULAR,',
'      :P6_NOMENCLATURA,',
'      :P6_CUIL,',
'      :P6_RAZON_SOCIAL,',
'      :P6_INMUEBLE_CALLE,',
'      :P6_INMUEBLE_NUMERO,',
'      :P6_MANZANA,',
'      :P6_SECCION,',
'      :P6_PARCELA,',
'      :P6_TIPO_INMUEBLE,',
'      :P6_USO_INMUEBLE,',
'      :P6_METROS_CUADRADOS,',
'      :P6_RAZA,',
'      :P6_ESPECIE,',
'      :P6_SEXO,',
'      :P6_ANIMAL_ID_PROPIETARIO,',
'      :P6_MOTIVO_TIPO_ACTA,',
'      :P6_MOTIVO_DESCRIPCION,',
'      :P6_INSPECTOR_NOMBRE,',
'      :P6_INSPECTOR_APELLIDO,',
'      :P6_DEPARTAMENTO,',
'      :P6_CARGO,',
'      :P6_ID_DOC,',
'      :P6_TIPO_DOC,',
'      :P6_FECHA_GENERACION,',
'      :P6_USUARIO_GENERA',
'    FROM vw_multas_busqueda_completa',
'    WHERE id_acta = :P6_ID_ACTA_1;',
'  END IF;',
'EXCEPTION',
'  WHEN NO_DATA_FOUND THEN',
'    APEX_UTIL.REDIRECT_URL(',
'      ''f?p='' || :APP_ID || '':5:'' || :APP_SESSION',
'    );',
'END;',
''))
,p_process_clob_language=>'PLSQL'
,p_process_when=>'P6_ID_ACTA_1'
,p_process_when_type=>'ITEM_IS_NOT_NULL'
,p_internal_uid=>125016690674766289648
);
end;
