wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(125592051497648920722)
,p_plug_name=>'RESUMEN_CARNET'
,p_plug_display_sequence=>20
,p_location=>null
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'<div style="padding: 1rem; background-color: #f0f8ff; border: 1px solid #ccc; border-radius: 6px; text-align: center;">',
'  <strong>La consulta realizada no registra deudas en este Municipio.</strong>',
'</div>'))
,p_plug_display_condition_type=>'EXPRESSION'
,p_plug_display_when_condition=>wwv_flow_string.join(wwv_flow_t_varchar2(
':P10_IDENTIFICADOR IS NOT NULL',
'AND NOT EXISTS (',
'    SELECT 1',
'    FROM vw_multas_busqueda_completa v',
'    WHERE',
'        /* Multas vehiculares */',
'        v.id_vehiculo IS NOT NULL',
'',
unistr('        /* Persona vinculada al veh\00EDculo */'),
'    AND EXISTS (',
'            SELECT 1',
'            FROM personas p',
'            WHERE UPPER(TRIM(p.dni)) = UPPER(TRIM(:P10_IDENTIFICADOR))',
'              AND p.id_persona = v.vehiculo_id_titular',
'        )',
'',
'        /* Excluir multas resueltas */',
'    AND NVL(UPPER(v.estado), ''X'') <> ''RESUELTA''',
')'))
,p_plug_display_when_cond2=>'SQL'
,p_attributes=>wwv_flow_t_plugin_attributes(wwv_flow_t_varchar2(
  'expand_shortcuts', 'N',
  'output_as', 'HTML')).to_clob
);
