 p_id=>wwv_flow_imp.id(120601915306590179320)
,p_plug_name=>'Libre de Multa'
,p_plug_display_sequence=>30
,p_location=>null
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
unistr('<!-- Librer\00EDa html2pdf -->'),
'<script src="https://cdnjs.cloudflare.com/ajax/libs/html2pdf.js/0.10.1/html2pdf.bundle.min.js"></script>',
'',
'<!-- CONTENEDOR DEL CERTIFICADO -->',
'<div id="certificado-libre-multas" style="',
'  font-family: Arial, sans-serif;',
'  border: 2px solid #ccc;',
'  border-radius: 10px;',
'  padding: 30px;',
'  background-color: white;',
'  max-width: 800px;',
'  margin: 0 auto;',
'">',
'',
'  <!-- MEMBRETE -->',
'  <div style="text-align: center; margin-bottom: 20px;">',
'    <img src="#APP_FILES#membretesup.png"',
'         alt="Membrete"',
'         style="width: 100%; max-height: 120px; object-fit: contain;">',
'  </div>',
'',
unistr('  <!-- T\00CDTULO -->'),
'  <div style="text-align: center; margin-bottom: 20px;">',
'    <h2 style="margin: 0; font-size: 22px; text-transform: uppercase;">',
'      Certificado de Libre de Multas',
'    </h2>',
'  </div>',
'',
'  <!-- TEXTO PRINCIPAL -->',
'  <p style="font-size: 14px; text-align: justify; margin-bottom: 20px;">',
unistr('    La Municipalidad de Casilda certifica que al d\00EDa'),
'    <strong><span id="fecha-auto"></span></strong>,',
'    no se registran infracciones ni actas pendientes asociadas a',
'    <strong><span id="identificador-consulta"></span></strong>.',
'  </p>',
'',
'  <p style="font-size: 14px; text-align: justify;">',
unistr('    Este certificado ha sido generado autom\00E1ticamente a solicitud del interesado,'),
'    con fines informativos y administrativos.',
'  </p>',
'',
'  <!-- FIRMA Y SELLO -->',
'  <div style="display: flex; justify-content: flex-end; align-items: center; margin-top: 50px;">',
'    <div style="margin-right: 20px;">',
'      <img src="#APP_FILES#sello.png"',
'           alt="Sello"',
'           style="max-height: 80px;">',
'    </div>',
'    <div style="text-align: right; font-size: 12px;">',
'      _____________________________<br>',
'      Jefe del Departamento de Faltas',
'    </div>',
'  </div>',
'',
'  <!-- PIE -->',
'  <div style="text-align: center; font-size: 12px; margin-top: 40px; color: #333;">',
'    Tel: (54) (3464) 429080<br>',
unistr('    Web: www.casilda.gob.ar \2013 tribunaldefaltas@casilda.gob.ar<br>'),
unistr('    BUENOS AIRES 2860 \2013 S2170BYV \2013 CASILDA \2013 Santa Fe'),
'  </div>',
'',
'</div>',
'',
unistr('<!-- BOT\00D3N DESCARGA PDF -->'),
'<div style="text-align:center; margin-top:20px;">',
'  <button type="button"',
'          onclick="descargarPDFLibreMultas()"',
'          style="',
'            padding:10px 25px;',
'            font-size:14px;',
'            font-weight:bold;',
'            border:none;',
'            border-radius:6px;',
'            background:#000;',
'            color:#fff;',
'            cursor:pointer;',
'          ">',
'    Descargar PDF',
'  </button>',
'</div>',
'',
'<!-- SCRIPT -->',
'<script>',
'document.addEventListener("DOMContentLoaded", function () {',
'',
unistr('  /* Fecha autom\00E1tica */'),
'  const hoy = new Date();',
'  const fechaFormateada = hoy.toLocaleDateString("es-AR", {',
'    day: "2-digit",',
'    month: "2-digit",',
'    year: "numeric"',
'  });',
'',
'  const spanFecha = document.getElementById("fecha-auto");',
'  if (spanFecha) {',
'    spanFecha.textContent = fechaFormateada;',
'  }',
'',
'  /* Tipo e identificador recibidos en P20 */',
'  const tipoConsulta = "&P20_TIPO_CONSULTA.";',
'  const identificador = "&P20_IDENTIFICADOR.";',
'',
'  let textoFinal = identificador;',
'',
'  if (tipoConsulta === "PATENTE") {',
'    textoFinal = "la patente " + identificador;',
'  } else if (tipoConsulta === "NOMENCLATURA") {',
'    textoFinal = "la nomenclatura catastral " + identificador;',
'  } else if (tipoConsulta === "DNI") {',
'    textoFinal = "el DNI " + identificador;',
'  }',
'',
'  const spanIdentificador = document.getElementById("identificador-consulta");',
'  if (spanIdentificador) {',
'    spanIdentificador.textContent = textoFinal;',
'  }',
'});',
'',
unistr('/* Generaci\00F3n del PDF */'),
'function descargarPDFLibreMultas() {',
'',
'  const elemento = document.getElementById("certificado-libre-multas");',
'  if (!elemento) {',
unistr('    alert("No se encontr\00F3 el certificado.");'),
'    return;',
'  }',
'',
'  html2pdf().set({',
'    margin: 10,',
'    filename: ''LibreDeMultas_'' + ''&P20_IDENTIFICADOR.'' + ''.pdf'',',
'    image: { type: ''jpeg'', quality: 1.0 },',
'    html2canvas: { scale: 4, useCORS: true },',
'    jsPDF: { unit: ''mm'', format: ''a4'', orientation: ''portrait'' }',
'  }).from(elemento).save();',
'}',
'</script>',
''))
,p_attributes=>wwv_flow_t_plugin_attributes(wwv_flow_t_varchar2(
  'expand_shortcuts', 'N',
  'output_as', 'HTML')).to_clob
);
wwv_flow_imp_page.create_page_plug(
